import{c as i,Q as d,j as s,m as t}from"./chunks/framework.DVkeSyfh.js";const k=JSON.parse('{"title":"Скрипт отчёта и очистки дублей аудио","description":"","frontmatter":{},"headers":[],"relativePath":"ru/scripts/audio-dedup.md","filePath":"ru/scripts/audio-dedup.md","lastUpdated":1780038170000}'),a={name:"ru/scripts/audio-dedup.md"};function o(p,e,l,c,h,r){return d(),s("div",null,[...e[0]||(e[0]=[t(`<h1 id="скрипт-отчета-и-очистки-дублеи-аудио" tabindex="-1">Скрипт отчёта и очистки дублей аудио <a class="header-anchor" href="#скрипт-отчета-и-очистки-дублеи-аудио" aria-label="Permalink to &quot;Скрипт отчёта и очистки дублей аудио&quot;">​</a></h1><p>По возможности запускайте этот скрипт через проектное Python-окружение:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\audio_dedup\\audio_dedup.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">help</span></span></code></pre></div><p>Вспомогательный инструмент для дублей аудио с двумя режимами. По умолчанию он работает только как отчёт: читает существующую SQLite-базу <code>dj-track-similarity</code>, сравнивает треки внутри выбранного сохранённого корня путей и записывает отчёты JSON, оформленную книгу XLSX и текстовый лог. Отчёт также проверяет базу Rhythm Lab по умолчанию <code>tools\\rhythm-lab\\data\\rhythm_lab.sqlite</code> и перечисляет строки лаборатории, которые были бы удалены для безопасных кандидатов. JSON хранит компактный блок <code>rhythm_lab.summary</code> и подробные затронутые строки; текстовый лог пишет ту же сводку строкой <code>rhythm_lab_summary=...</code>.</p><p>С <code>--apply</code> добавляется подтверждённый проход очистки: после записи отчётов скрипт удаляет безопасные файлы-дубли и их строки в основной базе данных. Если база Rhythm Lab существует по пути по умолчанию, apply-режим также удаляет соответствующие строки лаборатории для удалённых <code>source_track_id</code>.</p><p>Используйте режим отчёта по умолчанию, когда нужны доказательства возможных дублей перед очисткой библиотеки. Он намеренно консервативен: отчёты всегда создаются первыми. Разрушительная очистка запускается только с <code>--apply</code> и интерактивным подтверждением, и удаляет только кандидатов, которых отчёт пометил как безопасных.</p><p>Использование:</p><div class="language-text vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>python scripts\\audio_dedup\\audio_dedup.py --root ROOT [OPTIONS]</span></span></code></pre></div><p>Параметры:</p><ul><li><code>--db DB</code>: SQLite-база проекта. По умолчанию <code>C:\\db\\abstracted.sqlite</code>.</li><li><code>--root ROOT</code>: обязательный сохранённый корень путей, ограничивающий треки для сравнения.</li><li><code>--path-contains TEXT</code>: дополнительный фильтр пути без учёта регистра. Можно указывать несколько раз.</li><li><code>--preset safe|balanced|aggressive</code>: пресет оценки. По умолчанию <code>safe</code>.</li><li><code>--min-score SCORE</code>: переопределить порог включения дубля из пресета.</li><li><code>--limit-groups N</code>: записать не более N групп дублей.</li><li><code>--out-dir DIR</code>: каталог отчётов. По умолчанию <code>scripts\\audio_dedup\\reports</code>.</li><li><code>--apply</code>: после записи отчётов запросить точную фразу подтверждения и удалить только кандидатов, помеченных как <code>DELETE CANDIDATE</code> / <code>true_candidate</code>. Строки треков удаляются из SQLite только после успешного удаления их аудиофайлов.</li></ul><h2 id="пресеты" tabindex="-1">Пресеты <a class="header-anchor" href="#пресеты" aria-label="Permalink to &quot;Пресеты&quot;">​</a></h2><p>Каждый пресет задаёт порог попадания в отчёт, более строгий порог прямого совпадения с keeper-треком для автоматического кандидата на удаление и строгость совпадения длительности. <code>--min-score</code> переопределяет только порог включения в отчёт; параметры безопасного удаления и длительности остаются как в таблице.</p><table tabindex="0"><thead><tr><th>Пресет</th><th>Мин. оценка</th><th>Оценка safe delete</th><th>Допуск длительности</th><th>Когда использовать</th></tr></thead><tbody><tr><td><code>safe</code></td><td><code>0.965</code></td><td><code>0.980</code></td><td>~2 с / 1% ratio</td><td>Консервативное обслуживание с минимальным числом ложных срабатываний.</td></tr><tr><td><code>balanced</code></td><td><code>0.950</code></td><td><code>0.970</code></td><td>~5 с / 2.5% ratio</td><td>Более широкий поиск, который всё ещё может помечать сильных кандидатов на удаление.</td></tr><tr><td><code>aggressive</code></td><td><code>0.925</code></td><td><code>0.965</code></td><td>~15 с / 8% ratio</td><td>Самый широкий поиск; ожидайте больше ручной проверки, но очень сильные прямые совпадения всё ещё могут стать delete candidates.</td></tr></tbody></table><h2 id="оценка" tabindex="-1">Оценка <a class="header-anchor" href="#оценка" aria-label="Permalink to &quot;Оценка&quot;">​</a></h2><p>Оценка пары объединяет доступные сигналы в одно значение <code>0..1</code>, нормализованное по весу сигналов, которые есть у обоих треков:</p><table tabindex="0"><thead><tr><th>Сигнал</th><th>Вес</th></tr></thead><tbody><tr><td>Сходство MERT embedding</td><td><code>0.43</code></td></tr><tr><td>Сходство MAEST embedding</td><td><code>0.32</code></td></tr><tr><td>Сходство признаков SONARA</td><td><code>0.14</code></td></tr><tr><td>Сходство CLAP embedding</td><td><code>0.04</code></td></tr><tr><td>Близость длительности</td><td><code>0.05</code></td></tr></tbody></table><p>Каждая группа получает уровень уверенности <code>high</code>, <code>medium</code> или <code>review</code> по оценке и блокирующим причинам. BPM/key из тегов показываются только как метаданные трека и никогда не используются для оценки дублей.</p><p>Примеры:</p><div class="language-powershell vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">powershell</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\audio_dedup\\audio_dedup.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library.sqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root D:\\Music</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\audio_dedup\\audio_dedup.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library.sqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root D:\\Music </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">preset balanced </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">path</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">-</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">contains mastered</span></span>
<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">.\\.venv\\Scripts\\</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">python.exe</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> scripts\\audio_dedup\\audio_dedup.py </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">db .\\</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">data</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">\\library.sqlite </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">root D:\\Music </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">preset safe </span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">--</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">apply</span></span></code></pre></div><p>Файлы вывода называются <code>audio_dedup_report_&lt;timestamp&gt;.json</code>, <code>.xlsx</code> и <code>.log</code>. Каталог отчётов по умолчанию игнорируется git.</p><p>После каждого запуска CLI печатает короткую сводку: число групп дублей, число безопасных кандидатов в режиме отчёта и сведения о базе Rhythm Lab/затронутых строках.</p><p>Книга XLSX является основным артефактом для ручной проверки. Она включает:</p><ul><li><code>Summary</code>: путь к базе данных, выбранный корень, пресет, порог оценки, общее число треков в базе, число треков внутри выбранного корня/фильтра, количество групп и кандидатов, разбивку уверенности (<code>high</code>/<code>medium</code>/<code>review</code>) и счётчики покрытия embeddings MERT/MAEST/CLAP.</li><li><code>Groups</code>: по одной строке на группу дублей, с предлагаемым <code>KEEP</code>-треком и причинами, почему он предпочтительнее остальных файлов.</li><li><code>Candidates</code>: по одной строке на кандидата, с действием <code>DELETE CANDIDATE</code> или <code>REVIEW MANUALLY</code>, путём keeper-трека, прямой оценкой, доказательствами сходства и блокерами проверки.</li><li><code>Pair Evidence</code>: подробные попарные доказательства MERT, MAEST, SONARA, CLAP и длительности, использованные при группировке. BPM/key из тегов показаны только как метаданные и не участвуют в оценке дублей; BPM из SONARA остаётся частью сигнала сходства SONARA, когда доступен.</li><li><code>Rhythm Lab</code>: строки в базе Rhythm Lab по умолчанию, которые apply-режим удалил бы для кандидатов, помеченных безопасными. Если базы нет или у безопасных кандидатов нет строк лаборатории, лист содержит только заголовки.</li></ul><p>Проверяйте каждого кандидата вручную; отчёт содержит предлагаемые keeper-треки и доказательства для удаления кандидатов.</p><p>Apply-режим:</p><ol><li>Скрипт сначала записывает отчёты JSON/XLSX/лог.</li><li>Он считает только безопасных кандидатов на удаление.</li><li>Печатает предупреждение о разрушительном действии и требует ввести точно <code>APPLY DELETE</code>.</li><li>Удаляет только файлы, которые всё ещё находятся внутри выбранного <code>--root</code>.</li><li>Удаляет строки SQLite только для треков, чьи файлы были успешно удалены. Связанные строки в таблицах со столбцом <code>track_id</code> удаляются перед строкой <code>tracks</code>.</li><li>Открывает <code>tools\\rhythm-lab\\data\\rhythm_lab.sqlite</code>, если она существует, и удаляет строки, где <code>source_track_id</code> совпадает с успешно удалёнными track IDs. Это очищает ручные labels и predictions, не затрагивая classifier profiles и training checkpoints.</li><li>Перезаписывает JSON и лог с <code>mode = apply</code> и блоком <code>apply_result</code>, где перечислены удалённые track IDs, удалённые пути, пропущенные или неудачные удаления и число удалённых строк Rhythm Lab. Лог также пишет блок <code>deleted_files:</code> со строкой <code>deleted_file=...</code> для каждого файла, успешно удалённого с диска. Существующий блок <code>rhythm_lab.summary</code> в JSON остаётся pre-apply сводкой воздействия, показанной в книге.</li></ol><p>Если вы отклоните подтверждение, отчёты останутся на диске и ничего не будет удалено. Не используйте <code>--apply</code>, пока не проверите сгенерированную книгу. Автоматические тесты и рутинная проверка не должны запускать скрипт с <code>--apply</code>.</p><p>Для обычного обслуживания библиотеки начинайте с пресета <code>safe</code>. Используйте <code>balanced</code> или <code>aggressive</code> только если готовы проверять больше ложных срабатываний.</p>`,28)])])}const E=i(a,[["render",o]]);export{k as __pageData,E as default};
